blocks.body:
{
    "level": "A1",
    "intro": "W tym temacie poznasz <strong>zaimki podmiotowe</strong> i <strong>zaimki dopełnieniowe</strong>, czyli dwie formy zaimków osobowych, które pokazują, kto wykonuje czynność, a kto jest jej odbiorcą.",
    "rules": [
        {
            "label": "Podmiot",
            "color": "emerald",
            "text": "<strong>Zaimki podmiotowe</strong> mówią, kto coś robi:",
            "example": "I work. She reads. They play."
        },
        {
            "label": "Dopełnienie",
            "color": "blue",
            "text": "<strong>Zaimki dopełnieniowe</strong> pokazują, kogo albo co dotyczy czynność:",
            "example": "Call me. I see him. Tell us."
        },
        {
            "label": "Pozycja",
            "color": "amber",
            "text": "<strong>Pozycja w zdaniu</strong> pomaga wybrać poprawną formę:",
            "example": "Forma podmiotowa stoi zwykle przed czasownikiem, a dopełnieniowa po czasowniku lub przyimku."
        }
    ]
}

{
    "title": "1. Dwie formy zaimków osobowych",
    "intro": "Zaimki osobowe zmieniają formę w zależności od roli w zdaniu:",
    "items": [
        {
            "label": "Podmiot",
            "title": "Zaimki podmiotowe",
            "subtitle": "I, you, he, she, it, we, they stoją zwykle przed czasownikiem i mówią, kto wykonuje czynność"
        },
        {
            "label": "Dopełnienie",
            "title": "Zaimki dopełnieniowe",
            "subtitle": "me, you, him, her, it, us, them pojawiają się po czasowniku lub przyimku i mówią, kogo / co dotyczy czynność"
        }
    ]
}

{
    "title": "2. Zaimki podmiotowe: I, you, he, she...",
    "sections": [
        {
            "label": "Do czego służą?",
            "color": "emerald",
            "description": "<strong>Zaimki podmiotowe</strong> pełnią funkcję podmiotu, czyli pokazują, kto wykonuje czynność. Najczęściej stoją <strong>przed czasownikiem</strong>.",
            "examples": [
                {
                    "en": "I work every day.",
                    "ua": "Pracuję codziennie."
                },
                {
                    "en": "You are smart.",
                    "ua": "Jesteś bystry / Jesteście bystrzy."
                },
                {
                    "en": "He lives in Kyiv.",
                    "ua": "On mieszka w Kijowie."
                },
                {
                    "en": "She speaks English.",
                    "ua": "Ona mówi po angielsku."
                },
                {
                    "en": "It is a cat.",
                    "ua": "To jest kot."
                },
                {
                    "en": "We study together.",
                    "ua": "Uczymy się razem."
                },
                {
                    "en": "They play football.",
                    "ua": "Oni grają w piłkę nożną."
                }
            ]
        },
        {
            "label": "I zawsze wielką literą",
            "color": "sky",
            "description": "Zaimek <strong>I</strong> zapisujemy wielką literą, nawet w środku zdania.",
            "examples": [
                {
                    "en": "I like coffee.",
                    "ua": "Lubię kawę."
                },
                {
                    "en": "My friend and I went to the park.",
                    "ua": "Mój przyjaciel i ja poszliśmy do parku."
                },
                {
                    "en": "I am a student.",
                    "ua": "Jestem studentem."
                }
            ],
            "note": "W angielskim nie piszemy i małą literą, jeśli chodzi o zaimek I."
        },
        {
            "label": "You dla jednej i wielu osób",
            "color": "purple",
            "description": "<strong>You</strong> działa zarówno dla liczby pojedynczej, jak i mnogiej, w stylu formalnym i nieformalnym.",
            "examples": [
                {
                    "en": "You are my friend.",
                    "ua": "Jesteś moim przyjacielem."
                },
                {
                    "en": "You are welcome here.",
                    "ua": "Jesteście tu mile widziani."
                },
                {
                    "en": "Are you ready?",
                    "ua": "Jesteś gotowy? / Jesteście gotowi?"
                }
            ]
        },
        {
            "label": "He, she, it",
            "color": "amber",
            "description": "<strong>He</strong> odnosi się zwykle do mężczyzn, <strong>she</strong> do kobiet, a <strong>it</strong> do rzeczy, zwierząt i pojęć abstrakcyjnych.",
            "examples": [
                {
                    "en": "He is my brother.",
                    "ua": "On jest moim bratem."
                },
                {
                    "en": "She works in a bank.",
                    "ua": "Ona pracuje w banku."
                },
                {
                    "en": "It is raining.",
                    "ua": "Pada deszcz."
                },
                {
                    "en": "It is a good book.",
                    "ua": "To dobra książka."
                }
            ],
            "note": "It często pojawia się też przy pogodzie, czasie i odległości."
        },
        {
            "label": "We i they",
            "color": "rose",
            "description": "<strong>We</strong> oznacza grupę, do której należy mówiący. <strong>They</strong> oznacza grupę, do której mówiący nie należy.",
            "examples": [
                {
                    "en": "We love this city.",
                    "ua": "Kochamy to miasto."
                },
                {
                    "en": "They are students.",
                    "ua": "Oni są studentami."
                },
                {
                    "en": "We go to school together.",
                    "ua": "Chodzimy razem do szkoły."
                },
                {
                    "en": "They live in London.",
                    "ua": "Oni mieszkają w Londynie."
                }
            ]
        }
    ]
}

{
    "title": "3. Zaimki dopełnieniowe: me, him, us...",
    "sections": [
        {
            "label": "Do czego służą?",
            "color": "blue",
            "description": "<strong>Zaimki dopełnieniowe</strong> pełnią funkcję dopełnienia, czyli pokazują, kogo albo co dotyczy czynność. Zwykle stoją <strong>po czasowniku albo po przyimku</strong>.",
            "examples": [
                {
                    "en": "Call me later.",
                    "ua": "Zadzwoń do mnie później."
                },
                {
                    "en": "I see you.",
                    "ua": "Widzę cię / was."
                },
                {
                    "en": "She loves him.",
                    "ua": "Ona go kocha."
                },
                {
                    "en": "Tell her the truth.",
                    "ua": "Powiedz jej prawdę."
                },
                {
                    "en": "Give it to me.",
                    "ua": "Daj mi to."
                },
                {
                    "en": "They invited us.",
                    "ua": "Zaprosili nas."
                },
                {
                    "en": "I know them well.",
                    "ua": "Dobrze ich znam."
                }
            ]
        },
        {
            "label": "Po czasownikach",
            "color": "sky",
            "description": "Po czasowniku używamy form typu <strong>me, him, her, us</strong>, a nie form podmiotowych.",
            "examples": [
                {
                    "en": "I like him.",
                    "ua": "Lubię go."
                },
                {
                    "en": "Help me, please.",
                    "ua": "Pomóż mi, proszę."
                },
                {
                    "en": "She knows us.",
                    "ua": "Ona nas zna."
                },
                {
                    "en": "I told them everything.",
                    "ua": "Powiedziałem im wszystko."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "purple",
            "description": "Po przyimkach, takich jak <strong>with, for, to, about</strong>, zawsze stawiamy <strong>formy dopełnieniowe</strong>.",
            "examples": [
                {
                    "en": "Come with me.",
                    "ua": "Chodź ze mną."
                },
                {
                    "en": "This is for you.",
                    "ua": "To jest dla ciebie / dla was."
                },
                {
                    "en": "Talk to him.",
                    "ua": "Porozmawiaj z nim."
                },
                {
                    "en": "She is thinking about her.",
                    "ua": "Ona myśli o niej."
                },
                {
                    "en": "They are looking at us.",
                    "ua": "Patrzą na nas."
                }
            ],
            "note": "Po with, for czy to nie używamy I / he / she, tylko me / him / her."
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "W krótkich, potocznych odpowiedziach bardzo często pojawiają się właśnie formy dopełnieniowe.",
            "examples": [
                {
                    "en": "Who did it? — Me.",
                    "ua": "Kto to zrobił? — Ja."
                },
                {
                    "en": "Who wants coffee? — Me!",
                    "ua": "Kto chce kawy? — Ja!"
                },
                {
                    "en": "Who is she talking to? — Him.",
                    "ua": "Z kim ona rozmawia? — Z nim."
                }
            ],
            "note": "W bardzo formalnym stylu można spotkać inne rozwiązania, ale w codziennym angielskim Me / him brzmią naturalnie."
        }
    ]
}

{
    "title": "4. Tabela: podmiot i dopełnienie",
    "intro": "Najważniejsze pary zaimków osobowych:",
    "rows": [
        {
            "en": "I",
            "ua": "ja (podmiot)",
            "note": "me = mnie / mi"
        },
        {
            "en": "you",
            "ua": "ty / wy (podmiot)",
            "note": "you = ciebie / was"
        },
        {
            "en": "he",
            "ua": "on (podmiot)",
            "note": "him = jego / mu"
        },
        {
            "en": "she",
            "ua": "ona (podmiot)",
            "note": "her = ją / jej"
        },
        {
            "en": "it",
            "ua": "to / ono (podmiot)",
            "note": "it = to / je"
        },
        {
            "en": "we",
            "ua": "my (podmiot)",
            "note": "us = nas / nam"
        },
        {
            "en": "they",
            "ua": "oni / one (podmiot)",
            "note": "them = ich / im"
        }
    ],
    "warning": "You i it mają taką samą formę jako podmiot i jako dopełnienie."
}

{
    "title": "5. Jak wybrać właściwą formę?",
    "sections": [
        {
            "label": "Zapytaj: kto? co?",
            "color": "emerald",
            "description": "Jeśli zaimek odpowiada na pytanie <strong>kto?</strong> albo <strong>co?</strong> jako wykonawca czynności, użyj formy podmiotowej.",
            "examples": [
                {
                    "en": "He called.",
                    "ua": "On zadzwonił."
                },
                {
                    "en": "She is here.",
                    "ua": "Ona tu jest."
                },
                {
                    "en": "They won.",
                    "ua": "Oni wygrali."
                }
            ]
        },
        {
            "label": "Zapytaj: kogo? komu?",
            "color": "blue",
            "description": "Jeśli zaimek odpowiada na pytanie <strong>kogo?</strong> albo <strong>komu?</strong>, wybierz formę dopełnieniową.",
            "examples": [
                {
                    "en": "He called me.",
                    "ua": "On zadzwonił do mnie."
                },
                {
                    "en": "I see her.",
                    "ua": "Widzę ją."
                },
                {
                    "en": "Tell them.",
                    "ua": "Powiedz im."
                }
            ]
        },
        {
            "label": "Sprawdź pozycję w zdaniu",
            "color": "amber",
            "description": "Przed czasownikiem zwykle stoi <strong>forma podmiotowa</strong>, a po czasowniku albo przyimku <strong>forma dopełnieniowa</strong>.",
            "examples": [
                {
                    "en": "I like him.",
                    "ua": "I jest podmiotem, him jest dopełnieniem."
                },
                {
                    "en": "She helps us.",
                    "ua": "She jest podmiotem, us jest dopełnieniem."
                },
                {
                    "en": "They know me.",
                    "ua": "They jest podmiotem, me jest dopełnieniem."
                }
            ],
            "note": "Gdy masz wątpliwość, najpierw zobacz, gdzie zaimek stoi w zdaniu."
        }
    ]
}

{
    "title": "6. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Mylenie form podmiotowych i dopełnieniowych.",
            "wrong": "Me and John went to the park. / Her is my friend.",
            "right": "✅ <span class=\"font-mono\">John and I went to the park. / She is my friend.<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Forma podmiotowa po przyimku.",
            "wrong": "Come with I. / This is for he.",
            "right": "✅ <span class=\"font-mono\">Come with me. / This is for him.<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Forma dopełnieniowa jako podmiot.",
            "wrong": "Him likes pizza. / Them are students.",
            "right": "✅ <span class=\"font-mono\">He likes pizza. / They are students.<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "I zapisane małą literą.",
            "wrong": "Yesterday i went to school.",
            "right": "✅ <span class=\"font-mono\">Yesterday I went to school.<\/span>"
        }
    ]
}

{
    "title": "8. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny zaimek",
    "select_intro": "Uzupełnij zdania odpowiednią formą zaimka podmiotowego albo dopełnieniowego.",
    "selects": [
        {
            "label": "___ am a student. (I / me)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "Call ___ later. (I / me)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "___ is my friend. (She / Her)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "Come with ___. (we / us)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "___ like pizza. (They / Them)",
            "prompt": "Która forma pasuje?"
        }
    ],
    "options": [
        "I",
        "me",
        "he",
        "him",
        "she",
        "her",
        "we",
        "us",
        "they",
        "them"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij zdania",
    "input_intro": "Wpisz poprawny zaimek.",
    "inputs": [
        {
            "before": "___ work every day. (ja pracuję)",
            "after": "→"
        },
        {
            "before": "Tell ___ the truth. (powiedz jej)",
            "after": "→"
        },
        {
            "before": "___ are friends. (my jesteśmy przyjaciółmi)",
            "after": "→"
        },
        {
            "before": "I know ___. (znam ich)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w użyciu zaimka.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Me like ice cream.",
            "example_target": "I like ice cream."
        },
        {
            "original": "1. Her is my sister.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. Come with I.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "3. Them are students.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Zaimki",
            "current": false
        },
        {
            "label": "Osobowe i dopełnieniowe",
            "current": true
        },
        {
            "label": "Formy dzierżawcze",
            "current": false
        },
        {
            "label": "Zaimki zwrotne",
            "current": false
        }
    ]
}
